import{c as e,i as t,n,o as r,r as i,s as a,t as o}from"./app-X_Kuuhdi.js";var s=JSON.parse(`{"path":"/humanities/rongorongo.html","title":"롱고롱고(Rongorongo)","lang":"ko-KR","frontmatter":{"description":"롱고롱고(Rongorongo) Rongorongo 문자가 새겨진 목판 개요 Rongorongo는 🇨🇱 칠레 이스터 섬(Rapa Nui)에서 발견된 미해독 문자 체계 19세기 유럽인에 의해 처음 보고되었으며, 이스터 섬 토착민들이 사용했을 것으로 추정 현재까지 이 문자가 실제 음소 문자 체계인지, 단순한 기호 체계...","permalink":"/humanities/rongorongo","head":[["script",{"type":"application/ld+json"},"{\\"@context\\":\\"https://schema.org\\",\\"@type\\":\\"Article\\",\\"headline\\":\\"롱고롱고(Rongorongo)\\",\\"image\\":[\\"https://upload.wikimedia.org/wikipedia/en/thumb/2/2d/Rongorongo_B-v_Aruku-Kurenga_%28color%29_edit1.jpg/500px-Rongorongo_B-v_Aruku-Kurenga_%28color%29_edit1.jpg\\"],\\"dateModified\\":\\"2026-06-12T20:48:55.000Z\\",\\"author\\":[]}"],["meta",{"property":"og:url","content":"https://kmbzn.com/humanities/rongorongo"}],["meta",{"property":"og:title","content":"롱고롱고(Rongorongo)"}],["meta",{"property":"og:description","content":"롱고롱고(Rongorongo) Rongorongo 문자가 새겨진 목판 개요 Rongorongo는 🇨🇱 칠레 이스터 섬(Rapa Nui)에서 발견된 미해독 문자 체계 19세기 유럽인에 의해 처음 보고되었으며, 이스터 섬 토착민들이 사용했을 것으로 추정 현재까지 이 문자가 실제 음소 문자 체계인지, 단순한 기호 체계..."}],["meta",{"property":"og:type","content":"article"}],["meta",{"property":"og:image","content":"https://upload.wikimedia.org/wikipedia/en/thumb/2/2d/Rongorongo_B-v_Aruku-Kurenga_%28color%29_edit1.jpg/500px-Rongorongo_B-v_Aruku-Kurenga_%28color%29_edit1.jpg"}],["meta",{"property":"og:locale","content":"ko-KR"}],["meta",{"property":"og:updated_time","content":"2026-06-12T20:48:55.000Z"}],["meta",{"property":"article:modified_time","content":"2026-06-12T20:48:55.000Z"}]]},"git":{"createdTime":1750364500000,"updatedTime":1781297335000,"contributors":[{"name":"kmbzn","username":"kmbzn","email":"kmbzn24@gmail.com","commits":4,"url":"https://github.com/kmbzn"},{"name":"Claude Sonnet 4.6","username":"","email":"noreply@anthropic.com","commits":1}],"changelog":[{"hash":"47b5aed4ca177bf4af7be2a57306ea9a97ab434f","time":1781297335000,"email":"kmbzn24@gmali.com","author":"kmbzn","message":"0613_final"},{"hash":"867901d169b73496a8a67d2853b6d0b27bdbf876","time":1781277144000,"email":"kmbzn24@gmail.com","author":"kmbzn","message":"docs: rename all files to lowercase and add Products/Finance articles","coAuthors":[{"name":"Claude Sonnet 4.6","email":"noreply@anthropic.com"}]},{"hash":"e3e5343312fbd8ffce849661685f5bb7d47a5677","time":1750364798000,"email":"kmbzn24@gmail.com","author":"kmbzn","message":"update rongo"},{"hash":"6b13b4a75d0cc9927309f93dffbec9d80e04fdb3","time":1750364500000,"email":"kmbzn24@gmail.com","author":"kmbzn","message":"update rongorongo"}]},"filePathRelative":"humanities/rongorongo.md","autoDesc":true}`),c={name:`rongorongo.md`},l={class:`print-section`};function u(o,s,c,u,d,f){let p=e(`DateMeta`);return a(),i(`div`,null,[n(`section`,l,[s[0]||=n(`h1`,{id:`롱고롱고-rongorongo`,tabindex:`-1`},[n(`a`,{class:`header-anchor`,href:`#롱고롱고-rongorongo`},[n(`span`,null,`롱고롱고(Rongorongo)`)])],-1),r(p),s[1]||=n(`p`,null,[n(`img`,{src:`https://upload.wikimedia.org/wikipedia/en/thumb/2/2d/Rongorongo_B-v_Aruku-Kurenga_(color)_edit1.jpg/500px-Rongorongo_B-v_Aruku-Kurenga_(color)_edit1.jpg`,alt:`Rongorongo 문자가 새겨진 목판`})],-1)]),s[2]||=t(`<section class="print-section"><h2 id="개요" tabindex="-1"><a class="header-anchor" href="#개요"><span>개요</span></a></h2><ul><li>Rongorongo는 🇨🇱 칠레 이스터 섬(Rapa Nui)에서 발견된 미해독 문자 체계</li><li>19세기 유럽인에 의해 처음 보고되었으며, 이스터 섬 토착민들이 사용했을 것으로 추정</li><li>현재까지 이 문자가 실제 음소 문자 체계인지, 단순한 기호 체계인지 확실히 해석된 바 없음</li></ul></section><section class="print-section"><h2 id="특징" tabindex="-1"><a class="header-anchor" href="#특징"><span>특징</span></a></h2><ul><li>목재판에 사람, 동물, 식물, 기하 도형 등의 기호가 새겨져 있음</li><li>다체로 역부스트로폰(boustrophedon) 방식으로 작성됨<br> (한 줄은 좌→우로, 다음 줄은 기기를 뒤집어 우→좌로 읽는 방식)</li><li>조각은 홈(fluted) 구조를 따라 새겨진 경우가 많음</li></ul></section><section class="print-section"><h2 id="제작-방식" tabindex="-1"><a class="header-anchor" href="#제작-방식"><span>제작 방식</span></a></h2><ul><li>도구: 상어 이빨, 흑요석 조각, 동물 뼈 등으로 조각</li><li>방법: 먼저 얕은 선으로 초벌선을 그은 후, 날카로운 도구로 조각해 마무리함</li></ul></section><section class="print-section"><h2 id="보존-상태" tabindex="-1"><a class="header-anchor" href="#보존-상태"><span>보존 상태</span></a></h2><ul><li>현재 약 25~30개의 rongorongo 목판이 전 세계 박물관에 존재</li><li>대부분은 19세기 후반 유럽인 탐험가에 의해 반출됨</li><li>화산섬의 습한 기후와 목재 재질로 인해 상당수가 손상되었거나 마모됨</li></ul></section><section class="print-section"><h2 id="해독-시도" tabindex="-1"><a class="header-anchor" href="#해독-시도"><span>해독 시도</span></a></h2><ul><li>지금까지 <strong>아무도 이 문자를 완전히 해독하지 못함</strong></li><li>일부 기호는 반복 패턴이나 특정 인물, 장소, 행동을 나타낼 가능성이 제기됨</li><li>이스터 섬 언어(라파누이어) 및 폴리네시아어와의 연관성도 검토 중이나, 직접적 대응 관계는 <strong>확인되지 않음</strong></li></ul></section><section class="print-section"><h2 id="문화적-의미" tabindex="-1"><a class="header-anchor" href="#문화적-의미"><span>문화적 의미</span></a></h2><ul><li>이스터 섬 사회에서 종교, 의례, 족보 등에 관련된 정보를 담았을 것으로 추정됨</li><li>일부 학자들은 rongorongo를 성직자 집단에 의해 제한적으로 사용된 문자라 보기도 함</li><li>서양과의 접촉 이후 사용이 급격히 중단된 것으로 보이며, 19세기 말에는 해독 가능한 현지인도 남지 않게 되었음</li></ul></section><section class="print-section"><h2 id="대표-유물" tabindex="-1"><a class="header-anchor" href="#대표-유물"><span>대표 유물</span></a></h2><ul><li>태블릿 종류: London Tablet, Santiago Staff, Mamari Tablet 등</li><li>Santiago Staff는 가장 긴 텍스트가 포함되어 있으며, 약 2,300개의 기호가 새겨져 있음</li></ul></section><section class="print-section"><h2 id="관련-위치-google-maps" tabindex="-1"><a class="header-anchor" href="#관련-위치-google-maps"><span>관련 위치 (Google Maps)</span></a></h2><iframe src="https://www.google.com/maps/embed?pb=!1m18!1m12!1m3!1d53305.16754006754!2d-109.3831485!3d-27.1127238!2m3!1f0!2f0!3f0!3m2!1i1024!2i768!4f13.1!3m3!1m2!1s0x9947d2214645eb8f%3A0x617a72132a07b16f!2sEaster%20Island!5e0!3m2!1sen!2sus!4v1718900000000!5m2!1sen!2sus" width="100%" height="400" style="border:0;" loading="lazy" referrerpolicy="no-referrer-when-downgrade"></iframe></section><section class="print-section"><h2 id="authorship-and-translation-info" tabindex="-1"><a class="header-anchor" href="#authorship-and-translation-info"><span>Authorship and Translation Info</span></a></h2><ul><li><strong>Translated and compiled by</strong>: <a href="https://kmbzn.com/" target="_blank" rel="noopener noreferrer">kmbzn</a></li><li><strong>Date of initial translation</strong>: June 2025</li><li><strong>Original source</strong>: <a href="https://en.wikipedia.org/wiki/Rongorongo" target="_blank" rel="noopener noreferrer">Wikipedia - Rongorongo</a></li><li><strong>Disclaimer</strong>: This document is based on content from Wikipedia and is distributed under the Creative Commons Attribution-ShareAlike License. The rights of the original authors are respected.</li></ul></section>`,9)])}var d=o(c,[[`render`,u]]);export{s as _pageData,d as default};